<script setup lang="ts">
import { computed, ref } from "vue";
import { diffLines } from "diff";
import { message } from "@tauri-apps/plugin-dialog";
import MarkdownEditor from "./components/MarkdownEditor.vue";
import { useDocumentStore } from "./stores/document";
import { promoteSection, demoteSection, shiftSectionNumber, deleteSection, moveSection, autoNumberSections, renumberSections } from "./core/sections";
import { chooseMarkdownFile, chooseSavePath, fileNameFromPath, readMarkdown, writeMarkdown } from "./services/nativeFiles";
const store = useDocumentStore(); const leftTab = ref<"structure" | "diagnostics" | "history">("structure"); const rightTab = ref<"preview" | "diff">("preview"); const status = ref("新建空白 Markdown 文档");
const diffs = computed(() => diffLines(store.baseline, store.text));
function act(label: string, task: (id: string) => ReturnType<typeof promoteSection>) { if (!store.selectedSectionId) { status.value = "请先在结构面板选择章节"; return; } try { store.run(label, task(store.selectedSectionId)); status.value = `${label}已应用，可撤销`; } catch (error) { status.value = error instanceof Error ? error.message : "操作失败"; } }
function render(markdown: string) { return markdown.replace(/&/g, "&amp;").replace(/</g, "&lt;").replace(/^###### (.*)$/gm, "<h6>$1</h6>").replace(/^##### (.*)$/gm, "<h5>$1</h5>").replace(/^#### (.*)$/gm, "<h4>$1</h4>").replace(/^### (.*)$/gm, "<h3>$1</h3>").replace(/^## (.*)$/gm, "<h2>$1</h2>").replace(/^# (.*)$/gm, "<h1>$1</h1>").replace(/`([^`]+)`/g, "<code>$1</code>").replace(/\n/g, "<br>"); }
function applySafe() { try { store.applySafeFixes(); status.value = "已应用安全修复（一个可撤销事务）"; rightTab.value = "diff"; } catch (error) { status.value = error instanceof Error ? error.message : "安全修复无法应用"; } }
function undo() { store.undo(); status.value = "已撤销"; }
function redo() { store.redo(); status.value = "已重做"; }
async function saveDocument(copy = false): Promise<boolean> { try { const path = copy || !store.filePath ? await chooseSavePath(store.filePath ?? store.fileName) : store.filePath; if (!path) return false; await writeMarkdown(path, store.text); if (!copy) { store.markSaved(path, fileNameFromPath(path)); status.value = `已保存到 ${fileNameFromPath(path)}`; } else status.value = `已导出副本 ${fileNameFromPath(path)}`; return true; } catch (error) { status.value = error instanceof Error ? `保存失败：${error.message}` : "保存失败"; return false; } }
async function resolveUnsavedChanges(): Promise<boolean> { if (!store.dirty) return true; try { const result = String(await message("当前文档有未保存的修改。", { title: "保存修改？", kind: "warning", buttons: { yes: "保存", no: "放弃修改", cancel: "取消" } })).toLowerCase(); if (result === "yes") return saveDocument(); return result === "no"; } catch (error) { status.value = error instanceof Error ? error.message : "无法显示未保存修改提示"; return false; } }
async function newDocument() { if (!await resolveUnsavedChanges()) return; store.loadDocument(""); rightTab.value = "preview"; status.value = "已新建空白 Markdown 文档"; }
async function openDocument() { if (!await resolveUnsavedChanges()) return; try { const path = await chooseMarkdownFile(); if (!path) return; const content = await readMarkdown(path); store.loadDocument(content, { filePath: path, fileName: fileNameFromPath(path) }); rightTab.value = "preview"; status.value = `已打开 ${fileNameFromPath(path)}`; } catch (error) { status.value = error instanceof Error ? `打开失败：${error.message}` : "打开文件失败"; } }
function loadPastedDocument(value: string) { store.loadPastedDocument(value); rightTab.value = "diff"; status.value = "已将粘贴源码作为新的对比基线载入"; }
</script>
<template>
  <main class="shell">
    <header><div><span class="brand-mark">§</span><strong>mdTool</strong><small>Markdown STRUCTURE REPAIR</small><em>{{ store.fileName }}</em></div><div class="actions"><span :class="{ dirty: store.dirty }">{{ store.dirty ? "● 未保存" : store.filePath ? "○ 已保存" : "○ 未命名" }}</span><button @click="newDocument">新建</button><button @click="openDocument">打开</button><button @click="() => saveDocument()">保存</button><button @click="() => saveDocument(true)">另存为</button><button :disabled="!store.history.canUndo" @click="undo">撤销</button><button :disabled="!store.history.canRedo" @click="redo">重做</button><button class="accent" @click="applySafe">应用安全修复</button><button @click="() => saveDocument(true)">导出副本</button></div></header>
    <section class="workspace">
      <aside class="left"><nav><button :class="{ active: leftTab === 'structure' }" @click="leftTab = 'structure'">结构</button><button :class="{ active: leftTab === 'diagnostics' }" @click="leftTab = 'diagnostics'">诊断 <b>{{ store.diagnostics.length }}</b></button><button :class="{ active: leftTab === 'history' }" @click="leftTab = 'history'">历史</button></nav>
        <div v-if="leftTab === 'structure'" class="panel"><p class="eyebrow">章节树</p><button v-for="item in store.sections" :key="item.id" class="section" :class="{ selected: store.selectedSectionId === item.id }" :style="{ paddingLeft: `${(item.level - 1) * 14 + 8}px` }" @click="store.selectedSectionId = item.id"><span>{{ '#'.repeat(item.level) }}</span>{{ item.numberParts?.join('.') }} {{ item.title }}</button><div class="command-grid"><button @click="act('提升章节', id => promoteSection(store.text, id))">提升</button><button @click="act('降级章节', id => demoteSection(store.text, id))">降级</button><button @click="act('编号加一', id => shiftSectionNumber(store.text, id, 1))">编号 +1</button><button @click="act('编号减一', id => shiftSectionNumber(store.text, id, -1))">编号 −1</button><button @click="act('上移章节', id => moveSection(store.text, id, 'up'))">上移</button><button @click="act('下移章节', id => moveSection(store.text, id, 'down'))">下移</button><button @click="act('删除完整章节', id => deleteSection(store.text, id))">删除章节</button><button @click="store.run('自动生成标题编号', autoNumberSections(store.text))">自动编号</button><button @click="store.run('连续标题编号', renumberSections(store.text, store.selectedSectionId))">连续编号</button></div></div>
        <div v-else-if="leftTab === 'diagnostics'" class="panel"><p class="eyebrow">问题列表</p><button v-for="item in store.diagnostics" :key="item.id" class="issue" @click="rightTab = 'diff'"><i :class="item.severity"></i><span>{{ item.message }}</span><small>{{ item.ruleId }}</small></button><p v-if="!store.diagnostics.length" class="empty">未发现问题</p></div>
        <div v-else class="panel"><p class="eyebrow">操作历史</p><div v-for="entry in store.history.list()" :key="entry.at" class="history"><strong>{{ entry.label }}</strong><small>{{ entry.edits.length }} 处修改</small></div></div>
      </aside>
      <section class="source"><div class="pane-title"><span>源码</span><small>{{ store.fileName }}</small></div><MarkdownEditor :model-value="store.text" @update:model-value="store.replace" @paste-document="loadPastedDocument" @undo="undo" @redo="redo" /></section>
      <aside class="right"><nav><button :class="{ active: rightTab === 'preview' }" @click="rightTab = 'preview'">预览</button><button :class="{ active: rightTab === 'diff' }" @click="rightTab = 'diff'">差异</button></nav><article v-if="rightTab === 'preview'" class="preview" v-html="render(store.text)" /><article v-else class="diff"><p class="eyebrow">与当前文档基线对比（最近载入或保存）</p><p v-if="!store.dirty" class="empty">当前内容与对比基线一致</p><pre v-for="(part, i) in diffs" v-else :key="i" :class="{ added: part.added, removed: part.removed }">{{ part.value }}</pre></article></aside>
    </section><footer><span>{{ status }}</span><span>{{ store.text.length }} 字符 · {{ store.sections.length }} 个章节</span></footer>
  </main>
</template>
<style>
:root { font-family: "Microsoft YaHei UI", "Noto Sans CJK SC", sans-serif; color: #c6d2cf; background: #071012; } * { box-sizing: border-box; } body { margin: 0; min-width: 980px; } button { font: inherit; color: inherit; cursor: pointer; } .shell { height: 100vh; display: grid; grid-template-rows: 64px 1fr 28px; background: radial-gradient(circle at 65% -20%, #1d4640 0, transparent 30%), #071012; } header, footer { display: flex; align-items: center; justify-content: space-between; padding: 0 20px; border-bottom: 1px solid #20383a; background: #0a1517cc; } header > div:first-child { display: flex; align-items: baseline; gap: 10px; min-width: 0; } .brand-mark { color: #f1b75b; font: 700 30px/1 Georgia, "STSong", serif; } strong { font-family: Georgia, "STSong", serif; letter-spacing: .02em; } header small, .eyebrow, .pane-title small, footer, .issue small, .history small { font: 10px/1.2 Consolas, monospace; color: #78908c; letter-spacing: .1em; } header em { max-width: 180px; overflow: hidden; text-overflow: ellipsis; white-space: nowrap; color: #a9bbb6; font: 12px/1.2 "Cascadia Code", monospace; } .actions, nav { display: flex; gap: 8px; align-items: center; } .actions button, nav button, .command-grid button { border: 1px solid #315052; background: transparent; border-radius: 3px; padding: 6px 9px; font-size: 12px; } button:disabled { cursor: not-allowed; opacity: .38; } .actions .accent { background: #e6a845; border-color: #e6a845; color: #17201d; font-weight: 700; } .dirty { color: #f1b75b; }.workspace { min-height: 0; display: grid; grid-template-columns: 250px minmax(360px, 1fr) minmax(300px, .8fr); }.left, .right { min-height: 0; overflow: auto; background: #0c1719; }.left { border-right: 1px solid #20383a; }.right { border-left: 1px solid #20383a; } nav { height: 46px; padding: 8px 12px; border-bottom: 1px solid #20383a; } nav button { border: 0; color: #78908c; padding: 5px 7px; } nav button.active { color: #f1b75b; border-bottom: 1px solid #f1b75b; border-radius: 0; } nav b { color: #f1b75b; }.panel { padding: 14px 10px; }.eyebrow { margin: 0 0 12px; text-transform: uppercase; }.section, .issue { display: block; border: 0; background: none; text-align: left; width: 100%; padding: 7px 8px; border-radius: 3px; font-size: 13px; }.section span { color: #466b65; margin-right: 7px; font-size: 10px; }.section.selected { background: #153032; color: #f7cf80; }.command-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 6px; margin-top: 18px; }.command-grid button { text-align: left; color: #9db5ae; }.issue { display: grid; grid-template-columns: 8px 1fr; gap: 8px; }.issue small { grid-column: 2; font-size: 8px; }.issue i { display:block; width: 7px; height: 7px; margin-top: 4px; border-radius: 50%; }.issue i.error { background: #e26b5d; }.issue i.warning { background: #e6a845; }.issue i.info { background: #5daab0; }.history { border-left: 2px solid #315052; padding: 2px 8px; margin: 10px 0; display: grid; gap: 4px; }.source { min-width: 0; min-height: 0; display: grid; grid-template-rows: 46px 1fr; }.pane-title { padding: 15px 18px; display:flex; justify-content:space-between; border-bottom: 1px solid #20383a; background: #0e1a1c; }.preview, .diff { padding: 24px; line-height: 1.85; color: #d5dfda; }.preview h1,.preview h2,.preview h3 { font-family: Georgia, "STSong", serif; color: #f3c36d; }.preview code { color: #f1b75b; background: #142326; padding: 2px 4px; }.diff pre { white-space: pre-wrap; margin: 0; padding: 4px 8px; font: 12px/1.55 Consolas, monospace; }.diff .added { background: #18382f; color: #aedac2; }.diff .removed { background: #3b2425; color: #e5b8b2; text-decoration: line-through; }.empty { color: #78908c; text-align: center; padding: 20px; } footer { border-top: 1px solid #20383a; border-bottom: 0; font-size: 11px; }
</style>
